import os
import time
import pytest
import can

IC_MSG_ID = 0x300
RECV_TIMEOUT = 0.5

@pytest.fixture(scope="session")
def can_bus():
    bus = can.Bus(interface=os.getenv("CAN_INTERFACE", "socketcan"), channel=os.getenv("CAN_CHANNEL", "can0"), bitrate=500000)
    yield bus
    bus.shutdown()

def get_high_beam_status(data: bytes) -> int:
    return (data[0] >> 1) & 0x01

def collect_ic_messages(bus, duration):
    end_time = time.time() + duration
    collected = []
    while time.time() < end_time:
        msg = bus.recv(timeout=RECV_TIMEOUT)
        if msg and msg.arbitration_id == IC_MSG_ID: collected.append(msg)
    return collected

