def test_tc_hb_002_high_beam_off(can_bus):
    msgs = collect_ic_messages(can_bus, 2)
    assert all(get_high_beam_status(m.data) == 0 for m in msgs)

def test_tc_hb_005_stability_on(can_bus):
    msgs = collect_ic_messages(can_bus, 10)
    assert all(get_high_beam_status(m.data) == 1 for m in msgs)

def test_tc_hb_006_stability_off(can_bus):
    msgs = collect_ic_messages(can_bus, 10)
    assert all(get_high_beam_status(m.data) == 0 for m in msgs)

